.team-sec{background:var(--teal-light)}
.team-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:clamp(16px,3vw,28px)}
.team-card{text-align:center;background:var(--bg-card);border-radius:var(--radius);padding:clamp(24px,3vw,32px) 20px;box-shadow:var(--sh-card);transition:transform .35s var(--ease)}
.team-card:hover{transform:translateY(-5px)}
.team-avatar{width:clamp(80px,12vw,110px);height:clamp(80px,12vw,110px);border-radius:50%;margin:0 auto 16px;display:flex;align-items:center;justify-content:center;font-size:clamp(28px,4vw,38px);font-weight:800;color:#fff;position:relative}
.team-avatar::after{content:'';position:absolute;inset:-4px;border-radius:50%;border:3px solid var(--teal);opacity:.25}
.team-avatar.a1{background:linear-gradient(135deg,var(--teal),#45A3A3)}
.team-avatar.a2{background:linear-gradient(135deg,var(--warm),#F0B890)}
.team-avatar.a3{background:linear-gradient(135deg,#6B8F71,#8DB092)}
.team-avatar.a4{background:linear-gradient(135deg,#7B6F9F,#9B8FC0)}
.team-card .name{font-weight:800;font-size:1.1rem;margin:0}
.team-card .role{font-size:13px;color:var(--teal);font-weight:700;margin:4px 0 8px}
.team-card .bio{font-size:13.5px;color:var(--ink-muted);margin:0;line-height:1.5}

/* ── GALERIE ── */
.gal-grid{display:grid;grid-template-columns:1.5fr 1fr 1fr;grid-template-rows:220px 220px;gap:12px}
.gal-grid figure{margin:0;border-radius:var(--radius-sm);overflow:hidden;position:relative;cursor:pointer}
.gal-grid figure:first-child{grid-row:1/span 2}
.gal-grid img{width:100%;height:100%;object-fit:cover;transition:transform .8s var(--ease)}
.gal-grid figure:hover img{transform:scale(1.06)}
.gal-grid figure .cap{position:absolute;bottom:0;left:0;right:0;padding:16px;background:linear-gradient(transparent,rgba(0,0,0,.65));color:#fff;font-size:13px;font-weight:600;opacity:0;transition:opacity .3s}
.gal-grid figure:hover .cap{opacity:1}
